//그리드의 숨김속성 타이틀 노출이벤트
scwin.f_showBizDom = function() {
    let doc = JSON.parse(gr_ctrt.getCurrentGridStyle());
    let header = doc.E.find(e => e.N === "w2:header");
    header.E.forEach(row => {
        row.E.forEach(col => {
            if (col.A.id === "column55") {
                if(col.A.hidden == "true"){
                    col.A.hidden = "false";

                }else{
                    col.A.hidden = "true";
                }
            }
        });
    });
    gr_ctrt.setGridStyle(doc);
};

